def category_report(records):
    """Return ``(category, count, total)`` rows sorted by total, highest first.

    Ties on total break alphabetically by category so output is stable.
    """
    stats = {}
    for r in records:
        count, total = stats.get(r["category"], (0, 0.0))
        stats[r["category"]] = (count + 1, total + r["value"])
    return sorted(
        ((category, count, total) for category, (count, total) in stats.items()),
        key=lambda row: (-row[2], row[0]),
    )


